const css=document.createElement('link');css.rel='stylesheet';css.href=new URL('./live-app.css',import.meta.url).href;document.head.appendChild(css);document.title='EVENTSible OS';document.body.innerHTML=`<section id="login" class="login-shell"><div class="login-copy"><div class="wordmark">EVENTS<b>i</b>BLE</div><div><span class="eyebrow" style="color:#f8dd7b">Excellence in Event Entertainment</span><h1>One place to run every unforgettable event.</h1><p>Quotes, bookings, Wedding Hero, Event Hero, client planning, communications, and event-day readiness—connected through one secure EVENTSible operating system.</p></div><div class="feature-row"><span>GigTracker</span><span>Wedding Hero</span><span>Event Hero</span><span>Client Portals</span></div></div><div class="login-panel-wrap"><div class="login-panel"><span class="eyebrow">Secure access</span><h2>Welcome back</h2><p>Enter your approved business email and we’ll send a one-time sign-in link.</p><form id="login-form"><label for="email">Business email</label><input id="email" type="email" required autocomplete="email"><button class="primary" type="submit">Email my sign-in link</button></form><div id="login-message" class="message hidden"></div></div></div></section><section id="dashboard" class="app hidden"><aside class="sidebar"><div><div class="wordmark">EVENTS<b>i</b>BLE</div><small>Operating System</small></div><nav><a class="active" href="#overview">Overview</a><a href="#events">Events</a><a href="#heroes">Wedding & Event Hero</a><a href="#automations">Automations</a></nav><div class="sidebar-foot"><span id="role" class="role">Owner</span><button id="logout" class="secondary">Sign out</button></div></aside><main id="overview"><div class="topbar"><div><span class="eyebrow">Owner dashboard</span><h1>Good to see you, Travis.</h1><p>Here is the current pulse of EVENTSible.</p></div></div><div id="error" class="error-box hidden"></div><section class="metrics"><article class="metric"><span>Active leads</span><b id="m-leads">0</b><small>Builder and direct inquiries</small></article><article class="metric"><span>Booked events</span><b id="m-booked">0</b><small>Confirmed in the system</small></article><article class="metric"><span>Planning now</span><b id="m-planning">0</b><small>Hero work in progress</small></article><article class="metric"><span>Needs attention</span><b id="m-attention">0</b><small>Payments, contracts, or help</small></article></section><section class="grid"><article class="panel" id="events"><div class="panel-head"><div><span class="eyebrow">GigTracker</span><h2>Upcoming events</h2></div></div><div id="event-content"></div></article><div class="stack"><article class="panel" id="heroes"><div class="panel-head"><div><span class="eyebrow">Hero center</span><h2>Planning progress</h2></div></div><div class="mini"><span>Wedding Hero</span><b id="wedding-count">0</b></div><div class="mini"><span>Event Hero</span><b id="event-count">0</b></div></article><article class="panel" id="automations"><div class="panel-head"><div><span class="eyebrow">Automation</span><h2>System status</h2></div><span class="live">● Live</span></div><ul class="checklist"><li>Builder facts sync</li><li>Quote-to-booking lifecycle</li><li>Hero auto-assignment</li><li>Portal workspace creation</li></ul></article></div></section></main></section>`;await import(new URL('./live-app.js',import.meta.url).href);